BEGIN TRANSACTION;
CREATE TABLE despesas (
	id INTEGER NOT NULL, 
	descricao VARCHAR(255) NOT NULL, 
	categoria VARCHAR(100) NOT NULL, 
	valor FLOAT NOT NULL, 
	data_vencimento DATE NOT NULL, 
	data_pagamento DATE, 
	parcela_atual INTEGER, 
	parcela_total INTEGER, 
	pago BOOLEAN, 
	observacoes TEXT, 
	recorrente BOOLEAN, 
	frequencia_recorrencia VARCHAR(20), 
	parcelas_restantes INTEGER, 
	household_id INTEGER, 
	created_by INTEGER, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), user_id INTEGER REFERENCES users(id), 
	PRIMARY KEY (id), 
	FOREIGN KEY(household_id) REFERENCES households (id), 
	FOREIGN KEY(created_by) REFERENCES users (id)
);
CREATE TABLE household_invites (
	id INTEGER NOT NULL, 
	household_id INTEGER NOT NULL, 
	invited_email VARCHAR(255) NOT NULL, 
	invited_by INTEGER NOT NULL, 
	status VARCHAR(20) NOT NULL, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(household_id) REFERENCES households (id), 
	FOREIGN KEY(invited_by) REFERENCES users (id)
);
CREATE TABLE households (
	id INTEGER NOT NULL, 
	nome VARCHAR(255) NOT NULL, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE investimentos (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	ticker VARCHAR(20) NOT NULL, 
	tipo VARCHAR(20) NOT NULL, 
	quantidade FLOAT NOT NULL, 
	preco_medio FLOAT NOT NULL, 
	data_compra DATE NOT NULL, 
	observacoes TEXT, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE metas (
	id INTEGER NOT NULL, 
	descricao VARCHAR(255) NOT NULL, 
	valor_alvo FLOAT NOT NULL, 
	valor_atual FLOAT NOT NULL, 
	prazo DATE, 
	concluida BOOLEAN, 
	household_id INTEGER, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), user_id INTEGER REFERENCES users(id), 
	PRIMARY KEY (id), 
	FOREIGN KEY(household_id) REFERENCES households (id)
);
CREATE TABLE notifications (
	id INTEGER NOT NULL, 
	titulo VARCHAR(255) NOT NULL, 
	mensagem TEXT NOT NULL, 
	tipo VARCHAR(50) NOT NULL, 
	lida BOOLEAN, 
	referencia_id INTEGER, 
	referencia_tipo VARCHAR(50), 
	household_id INTEGER, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), user_id INTEGER REFERENCES users(id), 
	PRIMARY KEY (id), 
	FOREIGN KEY(household_id) REFERENCES households (id)
);
CREATE TABLE orcamento_categorias (
	id INTEGER NOT NULL, 
	categoria VARCHAR(100) NOT NULL, 
	limite FLOAT NOT NULL, 
	mes INTEGER NOT NULL, 
	ano INTEGER NOT NULL, 
	household_id INTEGER, user_id INTEGER REFERENCES users(id), 
	PRIMARY KEY (id), 
	FOREIGN KEY(household_id) REFERENCES households (id)
);
CREATE TABLE payments (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	subscription_id INTEGER, 
	amount FLOAT NOT NULL, 
	currency VARCHAR(3) NOT NULL, 
	status VARCHAR(20) NOT NULL, 
	payment_method VARCHAR(20) NOT NULL, 
	stripe_payment_intent_id VARCHAR(255), 
	mercadopago_payment_id VARCHAR(255), 
	description TEXT, 
	payment_metadata TEXT, 
	error_message TEXT, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	FOREIGN KEY(subscription_id) REFERENCES subscriptions (id)
);
CREATE TABLE receitas (
	id INTEGER NOT NULL, 
	descricao VARCHAR(255) NOT NULL, 
	categoria VARCHAR(100) NOT NULL, 
	valor FLOAT NOT NULL, 
	data DATE NOT NULL, 
	observacoes TEXT, 
	household_id INTEGER, 
	created_by INTEGER, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), user_id INTEGER REFERENCES users(id), 
	PRIMARY KEY (id), 
	FOREIGN KEY(household_id) REFERENCES households (id), 
	FOREIGN KEY(created_by) REFERENCES users (id)
);
CREATE TABLE shared_accounts (
	id INTEGER NOT NULL, 
	owner_id INTEGER NOT NULL, 
	partner_id INTEGER, 
	partner_email VARCHAR(255) NOT NULL, 
	status VARCHAR(20) NOT NULL, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(owner_id) REFERENCES users (id), 
	FOREIGN KEY(partner_id) REFERENCES users (id)
);
CREATE TABLE subscriptions (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	"plan" VARCHAR(20) NOT NULL, 
	status VARCHAR(20) NOT NULL, 
	stripe_customer_id VARCHAR(255), 
	stripe_subscription_id VARCHAR(255), 
	mercadopago_customer_id VARCHAR(255), 
	mercadopago_subscription_id VARCHAR(255), 
	current_period_start DATETIME, 
	current_period_end DATETIME, 
	cancel_at_period_end BOOLEAN, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	UNIQUE (user_id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE users (
	id INTEGER NOT NULL, 
	nome VARCHAR(255) NOT NULL, 
	email VARCHAR(255) NOT NULL, 
	senha_hash VARCHAR(255) NOT NULL, 
	household_id INTEGER, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), plan VARCHAR(20) DEFAULT "free", 
	PRIMARY KEY (id), 
	FOREIGN KEY(household_id) REFERENCES households (id)
);
CREATE INDEX ix_households_id ON households (id);
CREATE UNIQUE INDEX ix_users_email ON users (email);
CREATE INDEX ix_users_id ON users (id);
CREATE INDEX ix_orcamento_categorias_household_id ON orcamento_categorias (household_id);
CREATE INDEX ix_orcamento_categorias_id ON orcamento_categorias (id);
CREATE INDEX ix_metas_id ON metas (id);
CREATE INDEX ix_metas_household_id ON metas (household_id);
CREATE INDEX ix_notifications_household_id ON notifications (household_id);
CREATE INDEX ix_notifications_id ON notifications (id);
CREATE INDEX ix_household_invites_invited_email ON household_invites (invited_email);
CREATE INDEX ix_household_invites_id ON household_invites (id);
CREATE INDEX ix_receitas_id ON receitas (id);
CREATE INDEX ix_receitas_household_id ON receitas (household_id);
CREATE INDEX ix_despesas_id ON despesas (id);
CREATE INDEX ix_despesas_household_id ON despesas (household_id);
CREATE INDEX ix_shared_accounts_id ON shared_accounts (id);
CREATE INDEX ix_investimentos_user_id ON investimentos (user_id);
CREATE INDEX ix_investimentos_id ON investimentos (id);
CREATE INDEX ix_subscriptions_id ON subscriptions (id);
CREATE INDEX ix_payments_id ON payments (id);
COMMIT;
